var d = msg.payload;
if (typeof d === 'string') {
    try { d = JSON.parse(d); } catch(e) { node.warn('Bad JSON: ' + msg.payload); return null; }
}
msg._sensorData = d;
var ts = d.ts || '';
msg.url = env.get('APPS_SCRIPT_URL') + '?key=' + encodeURIComponent(env.get('APPS_SCRIPT_KEY')) + '&action=lookup&ts=' + encodeURIComponent(ts);
msg.payload = '';
return msg;

var d = msg._sensorData;
if (msg.statusCode === 200) {
    try {
        var gps = JSON.parse(msg.payload);
        if (gps.lat !== null && gps.lat !== undefined) {
            d.lat = gps.lat;
            d.lon = gps.lon;
        }
    } catch(e) { }
}
// Hiking monitor at home has no GPS track — use garage front wall (H6-H7 midpoint).
// rssi_dbm is 0 for field readings (no WiFi); non-zero confirms home WiFi.
if (d.component === 'hiking-monitor' && (d.lat === null || d.lat === undefined) && d.rssi_dbm !== 0) {
    d.lat = 32.4612842;
    d.lon = -111.1183818;
}
msg.payload = d;
return msg;

// Parse payload
var d = msg.payload;
if (typeof d === 'string') {
    try { d = JSON.parse(d); } catch(e) { node.warn('Bad JSON: ' + msg.payload); return null; }
}

// Add source field
d.source = d.component;

// Compute dew point and heat index if temp + humidity available
if (d.temp_f != null && d.humidity_pct != null) {
    var temp_c = (d.temp_f - 32) * 5 / 9;
    var a = 17.27, b = 237.7;
    var gamma = (a * temp_c / (b + temp_c)) + Math.log(d.humidity_pct / 100);
    var dew_c = (b * gamma) / (a - gamma);
    d.dew_point_f = Math.round((dew_c * 9/5 + 32) * 10) / 10;

    var T = d.temp_f, H = d.humidity_pct;
    if (T >= 80 && H >= 40) {
        d.heat_index_f = Math.round((
            -42.379 + 2.04901523*T + 10.14333127*H
            - 0.22475541*T*H - 0.00683783*T*T - 0.05481717*H*H
            + 0.00122874*T*T*H + 0.00085282*T*H*H
            - 0.00000199*T*T*H*H
        ) * 10) / 10;
    } else {
        d.heat_index_f = Math.round((T + H/5 - 10.3) * 10) / 10;
    }
}

// Build HTTP POST
msg.url = env.get('APPS_SCRIPT_URL') + '?key=' + encodeURIComponent(env.get('APPS_SCRIPT_KEY'));
msg.method = 'POST';
msg.headers = {'Content-Type': 'application/json'};
msg.payload = JSON.stringify(d);
msg._component = d.component;
return msg;

var component = msg._component || 'unknown';
var payload = (typeof msg.payload === 'string') ? msg.payload : JSON.stringify(msg.payload);
var status = msg.statusCode || 0;

// 405 = Google redirect chain completed (POST redirected to output URL, row was appended)
if (status === 405 || status === 302) {
    return null;
}

try {
    var resp = JSON.parse(payload);
    if (resp.status === 'ok') {
        return null;
    } else {
        msg.payload = JSON.stringify({component:'node-red',category:'Alert',message:'Sheets error for ' + component + ': ' + (resp.message || payload)});
        return msg;
    }
} catch(e) {
    if (payload.indexOf('Page Not Found') >= 0 || payload.indexOf('unable to open') >= 0) {
        msg.payload = JSON.stringify({component:'node-red',category:'Alert',message:'Sheets URL unreachable for ' + component});
        return msg;
    }
    return null;
}
